refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
image = imresize(image, [240 320]);
gray = rgb2gray(image);

rangeImage = imlocalrange(gray, [9 9]);

subplot(1, 2, 1);
imshow(image);
title("Input");
subplot(1, 2, 2);
imshow(immat2gray(rangeImage));
title("Local range");
